import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut, ShieldCheck, FileText, Activity, UserPlus, Plus, X, Info, CheckCircle, Search, HelpCircle } from 'lucide-react';

const Login = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [activeTab, setActiveTab] = useState('services'); // Default to Services for new users
  const [showModal, setShowModal] = useState(false);

  // Simulated Services Data
  const services = [
    { id: 1, title: 'Medical License Renewal', desc: 'Full handling of state board paperwork and fee management.', time: '15-30 Days', icon: <FileText className="text-blue-500" /> },
    { id: 2, title: 'Insurance Enrollment', desc: 'Get paneled with major payers like BlueCross, Aetna, and Cigna.', time: '60-90 Days', icon: <ShieldCheck className="text-emerald-500" /> },
    { id: 3, title: 'DEA Certification', desc: 'Federal registration and compliance check for controlled substances.', time: '7 Days', icon: <CheckCircle className="text-orange-500" /> }
  ];

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) setIsLoggedIn(true);
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${isRegistering ? 'register' : 'login'}`, formData);
      if (!isRegistering) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
      } else {
        setIsRegistering(false);
      }
    } catch (err) { alert("Login failed. Check your credentials."); }
  };

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
        {/* Navbar */}
        <nav className="bg-white shadow-md p-4 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <h1 className="text-xl font-black text-blue-600 tracking-tight">QUAD SOLUTIONS</h1>
            <div className="flex gap-6 items-center">
               <button onClick={() => setActiveTab('services')} className={`text-sm font-bold ${activeTab === 'services' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-400'}`}>Service Info</button>
               <button onClick={() => setActiveTab('tracking')} className={`text-sm font-bold ${activeTab === 'tracking' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-400'}`}>My Requests</button>
               <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold text-sm flex items-center gap-1"><LogOut size={16}/> Logout</button>
            </div>
          </div>
        </nav>

        <main className="p-6 md:p-10 max-w-7xl mx-auto w-full">
          {/* SERVICE INFORMATION PAGE VIEW */}
          {activeTab === 'services' ? (
            <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="mb-10 text-center md:text-left">
                <h2 className="text-3xl font-black text-slate-900 mb-2">Credentialing Services</h2>
                <p className="text-slate-500">Select a service to start your onboarding process.</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {services.map(service => (
                  <div key={service.id} className="bg-white p-8 rounded-[2rem] shadow-xl shadow-slate-200/50 border border-slate-100 hover:-translate-y-2 transition-all duration-300">
                    <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center mb-6">
                      {service.icon}
                    </div>
                    <h3 className="text-xl font-extrabold text-slate-800 mb-3">{service.title}</h3>
                    <p className="text-slate-500 text-sm leading-relaxed mb-6">{service.desc}</p>
                    <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                      <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Est: {service.time}</span>
                      <button onClick={() => setShowModal(true)} className="text-blue-600 font-bold text-sm hover:underline">Apply Now →</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="mt-12 bg-blue-600 rounded-[2.5rem] p-8 md:p-12 text-white flex flex-col md:flex-row items-center gap-8 shadow-2xl shadow-blue-200">
                <div className="flex-1">
                  <h3 className="text-2xl font-black mb-4 flex items-center gap-2"><HelpCircle/> Need a custom package?</h3>
                  <p className="text-blue-100 opacity-90 leading-relaxed">If you are a multi-state provider or represent a clinic, our onboarding specialists can create a custom credentialing plan for you.</p>
                </div>
                <button className="bg-white text-blue-600 px-8 py-4 rounded-2xl font-black hover:bg-blue-50 transition whitespace-nowrap">Contact Specialist</button>
              </div>
            </section>
          ) : (
            /* TRACKING VIEW (Your Previous Dashboard) */
            <section className="animate-in fade-in duration-500">
               <h2 className="text-2xl font-black mb-6">Request Tracking</h2>
               <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
                 <p className="text-slate-400 text-center py-10 italic">You haven't submitted any requests yet. Visit the Services page to begin.</p>
               </div>
            </section>
          )}
        </main>

        {/* --- SERVICE REQUEST MODAL --- */}
        {showModal && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
            <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl p-10 relative overflow-hidden">
              <button onClick={() => setShowModal(false)} className="absolute top-6 right-6 text-slate-300 hover:text-slate-600 transition"><X size={28}/></button>
              <h2 className="text-2xl font-black text-slate-900 mb-2">Service Application</h2>
              <p className="text-slate-500 mb-8 text-sm">Fill in your license details to start the onboarding process.</p>
              
              <form onSubmit={(e) => { e.preventDefault(); alert("Request Sent!"); setShowModal(false); }} className="space-y-4">
                <input type="text" placeholder="License Number (NPI/State ID)" className="w-full p-4 bg-slate-50 rounded-2xl border-none focus:ring-2 focus:ring-blue-500" required />
                <input type="text" placeholder="State of Issuance" className="w-full p-4 bg-slate-50 rounded-2xl border-none focus:ring-2 focus:ring-blue-500" required />
                <div className="bg-slate-50 p-6 rounded-2xl border-2 border-dashed border-slate-200 text-center">
                  <p className="text-xs font-bold text-slate-400 mb-2 uppercase">Required: Upload License PDF</p>
                  <button type="button" className="text-blue-600 font-bold text-xs underline">Browse Files</button>
                </div>
                <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition">Submit Application</button>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- LOGIN UI (unchanged) ---
  return (
    <div className="flex items-center justify-center min-h-screen bg-slate-100 p-4 font-sans">
      <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl border-t-[10px] border-blue-600">
        <h2 className="text-4xl font-black text-center text-slate-900 mb-2">QuadSolutions</h2>
        <p className="text-center text-slate-400 font-medium mb-8">Professional Credentialing Portal</p>
        <form onSubmit={handleAuth} className="space-y-4">
          {isRegistering && <input type="text" placeholder="Full Name" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, name: e.target.value})} required />}
          <input type="email" placeholder="Email Address" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          <input type="password" placeholder="Password" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          <button className="w-full bg-blue-600 py-4 rounded-2xl text-white font-black text-lg shadow-lg hover:bg-blue-700 transition">{isRegistering ? "Create Account" : "Access Portal"}</button>
        </form>
        <button onClick={() => setIsRegistering(!isRegistering)} className="w-full mt-6 text-slate-400 font-bold text-sm hover:text-blue-600 transition">{isRegistering ? "Already a member? Login" : "Become a member? Register"}</button>
      </div>
    </div>
  );
};

export default Login;
